7	/// All GitHub API access goes through the `gh` CLI so we inherit its auth
8	/// (keyring/oauth) instead of handling tokens ourselves. v1 requirement:
9	/// `gh auth login` must have been run for the target.
10	fn api_base(gh: &GithubConfig) -> String {
11	    match gh.scope {
12	        Scope::Repo => format!("repos/{}", gh.target),
13	        Scope::Org => format!("orgs/{}", gh.target),
14	    }
15	}
