18	struct JitConfigResponse {
19	    encoded_jit_config: String,
20	    runner: JitRunner,
21	}
22	
23	#[derive(Debug, Deserialize)]
24	struct JitRunner {
25	    id: u64,
26	    name: String,
27	}
