70	impl std::fmt::Display for IsolationLevel {
71	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
72	        match self {
73	            IsolationLevel::Container => write!(f, "container"),
74	            IsolationLevel::Vm => write!(f, "vm"),
