79	impl Config {
80	    /// Sensible defaults derived from host capacity: half the RAM (bounded to
81	    /// [2 GiB, 16 GiB]) and half the cores, so a runaway job cannot take the
82	    /// host down — the failure mode that motivated this tool.
83	    pub fn defaults_for(plat: &Platform, target: String, scope: Scope) -> Config {
84	        let mem = (plat.total_mem_mb / 2).clamp(2048, 16384);
85	        let cpus = ((plat.cpus / 2).max(1)) as f64;
86	        Config {
87	            version: 1,
88	            github: GithubConfig { scope, target },
89	            runner: RunnerConfig {
90	                labels: vec!["self-hosted".into(), "ezgha".into()],
91	                count: 1,
92	                image: "ghcr.io/actions/actions-runner:latest".into(),
93	            },
94	            limits: Limits {
95	                memory_mb: mem,
96	                cpus,
97	                pids: 512,
98	                min_free_disk_gb: default_min_free_disk_gb(),
99	            },
100	            policy: Policy {
101	                minimum_isolation: IsolationLevel::Container,
102	            },
103	        }
104	    }
