106	    pub fn default_path() -> Result<PathBuf> {
107	        let dirs = ProjectDirs::from("org", "jleechanorg", "ezgha")
108	            .context("cannot determine config directory")?;
109	        Ok(dirs.config_dir().join("config.toml"))
110	    }
