112	    pub fn load(path: &PathBuf) -> Result<Config> {
113	        let raw = std::fs::read_to_string(path)
114	            .with_context(|| format!("no config at {} — run `ezgha init` first", path.display()))?;
115	        let cfg: Config = toml::from_str(&raw)
116	            .with_context(|| format!("invalid config at {}", path.display()))?;
117	        Ok(cfg)
118	    }
119	
120	    pub fn save(&self, path: &PathBuf) -> Result<()> {
121	        if let Some(parent) = path.parent() {
122	            std::fs::create_dir_all(parent)?;
123	        }
124	        std::fs::write(path, toml::to_string_pretty(self)?)?;
125	        Ok(())
126	    }
127	}
